def has_close_elements(floats: list[float], threshold: float) -> bool:
    if len(floats) < 2:
        return False
    if threshold <= 0:
        return False
    sorted_floats = sorted(floats)
    for i in range(len(sorted_floats) - 1):
        if sorted_floats[i + 1] - sorted_floats[i] < threshold:
            return True
    return False
